import pika
import subprocess
import shlex

def validate_command(command):
    # Define an allowlist of safe commands
    allowed_commands = {'ls', 'echo', 'date'}
    parts = shlex.split(command)
    if parts and parts[0] in allowed_commands:
        return True
    return False

def on_message(ch, method, properties, body):
    command = body.decode('utf-8')
    if validate_command(command):
        try:
            result = subprocess.run(shlex.split(command), check=True, capture_output=True, text=True)
            print(f"Command executed successfully: {result.stdout}")
        except subprocess.CalledProcessError as e:
            print(f"Command execution failed: {e.stderr}")
    else:
        print("Invalid command received, ignoring.")

def main():
    connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
    channel = connection.channel()
    channel.queue_declare(queue='task_queue', durable=True)

    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue='task_queue', on_message_callback=on_message, auto_ack=True)

